import React, { useState, useEffect } from 'react';
import { Package, Truck, CheckCircle, MapPin, Navigation } from 'lucide-react';

const SeguimientoPedido = ({ pedido, onFinalizar }) => {
  const [fase, setFase] = useState(1);
  const [porcentajeCamino, setPorcentajeCamino] = useState(0);

  useEffect(() => {
    // Simulación de avance del cadete (0% a 100%)
    const intervalo = setInterval(() => {
      setPorcentajeCamino(prev => {
        if (prev >= 100) {
          clearInterval(intervalo);
          return 100;
        }
        return prev + 1;
      });
    }, 200); // Velocidad del simulador

    const t1 = setTimeout(() => setFase(2), 3000); 
    const t2 = setTimeout(() => {
      setFase(3);
      setTimeout(() => { if (onFinalizar) onFinalizar(pedido.id); }, 4000);
    }, 20000);

    return () => { clearInterval(intervalo); clearTimeout(t1); clearTimeout(t2); };
  }, [pedido.id, onFinalizar]);

  // URL de Google Maps estática centrada en la zona de Tafí Viejo / Tucumán
  // En un entorno real, aquí usarías la API de Directions de Google
  const urlMapa = `https://www.google.com/maps/embed/v1/place?key=TU_API_KEY_AQUI&q=${pedido.direccion || 'Tafí+Viejo,Tucuman'}`;

  return (
    <div style={card}>
      <div style={header}>
        <div>
          <strong style={{display:'block'}}>Pedido #{pedido.id.slice(-6)}</strong>
          <small style={{color: '#64748b'}}>Destino: {pedido.direccion || "Tu ubicación"}</small>
        </div>
        <span style={fase === 3 ? {color: '#27ae60', fontWeight:'bold'} : {color: '#e67e22', fontWeight:'bold'}}>
          {fase === 1 ? 'Preparando...' : fase === 2 ? 'En Camino' : '¡Llegó!'}
        </span>
      </div>

      {/* MAPA DE SEGUIMIENTO */}
      <div style={mapContainer}>
        <iframe
          title="Mapa de seguimiento"
          width="100%"
          height="180"
          style={{ border: 0, borderRadius: '12px' }}
          loading="lazy"
          allowFullScreen
          src={`https://www.google.com/maps/embed/v1/view?key=TU_API_KEY_DE_GOOGLE&center=-26.7324,-65.2670&zoom=14&maptype=roadmap`}
        ></iframe>
        
        {/* Superposición del Cadete (Simulando movimiento sobre el mapa) */}
        {fase === 2 && (
          <div style={{
            ...cadeteIcon,
            left: `${porcentajeCamino}%`,
            transition: 'left 0.5s linear'
          }}>
            <Navigation size={20} fill="#e67e22" color="white" style={{ transform: 'rotate(90deg)' }} />
            <div style={tooltip}>Cadete en camino</div>
          </div>
        )}
      </div>
      
      <div style={stepper}>
        {[
          { id: 1, label: 'Local', icon: <Package size={18} /> },
          { id: 2, label: 'Viaje', icon: <Truck size={18} /> },
          { id: 3, label: 'Casa', icon: <CheckCircle size={18} /> }
        ].map((p) => (
          <div key={p.id} style={{ ...step, color: fase >= p.id ? '#e67e22' : '#cbd5e1' }}>
            <div style={{ ...circle, background: fase >= p.id ? '#e67e22' : '#f1f5f9' }}>
              {React.cloneElement(p.icon, { color: fase >= p.id ? 'white' : '#94a3b8' })}
            </div>
            <span style={{fontSize: '0.65rem', fontWeight: 'bold'}}>{p.label}</span>
          </div>
        ))}
      </div>

      <div style={footerInfo}>
        <div style={{display:'flex', alignItems:'center', gap: '5px'}}>
          <Truck size={14} /> 
          <span>Distancia total: <strong>{pedido.distancia} km</strong></span>
        </div>
        <span>ETA: <strong>{fase === 3 ? '0' : Math.max(1, 15 - Math.round(porcentajeCamino/7))} min</strong></span>
      </div>
    </div>
  );
};

// Estilos nuevos para el mapa y el icono
const mapContainer = { width: '100%', height: '180px', background: '#e2e8f0', borderRadius: '12px', marginBottom: '20px', position: 'relative', overflow: 'hidden' };
const cadeteIcon = { position: 'absolute', top: '50%', transform: 'translateY(-50%)', zIndex: 5, filter: 'drop-shadow(0 2px 4px rgba(0,0,0,0.3))' };
const tooltip = { position: 'absolute', bottom: '25px', left: '-30px', background: '#1e293b', color: 'white', padding: '3px 8px', borderRadius: '5px', fontSize: '0.6rem', whiteSpace: 'nowrap' };
const footerInfo = { marginTop: '15px', display: 'flex', justifyContent: 'space-between', fontSize: '0.75rem', color: '#475569', borderTop: '1px solid #f1f5f9', paddingTop: '10px' };

// (Mantener estilos anteriores de card, header, stepper, step, circle)
const card = { background: 'white', padding: '20px', borderRadius: '20px', border: '1px solid #e2e8f0', marginBottom: '15px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' };
const header = { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '15px' };
const stepper = { display: 'flex', justifyContent: 'space-between', padding: '0 10px' };
const step = { display: 'flex', flexDirection: 'column', alignItems: 'center', flex: 1 };
const circle = { width: '36px', height: '36px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '5px' };

export default SeguimientoPedido;
